INSERT OR REPLACE INTO settings (key, value) VALUES ('about_values', '[{"number":"01","title":"Performance First","description":"Every design decision starts with one question: Does this help athletes perform better?"},{"number":"02","title":"Athletes Designing for Athletes","description":"We are athletes ourselves, creating performance gear built from real training experience."},{"number":"03","title":"No-Compromise Quality","description":"Premium fabrics, precision stitching, and rigorous testing to ensure durability and performance."},{"number":"04","title":"Accessible Excellence","description":"Elite performance gear without unnecessary markups."}]');